INSERT INTO questoes (pergunta, opcoes, resposta, tema, subtema, dificuldade, comentario)
VALUES
('Qual é a meta pressórica recomendada para pacientes hipertensos de alto risco cardiovascular, segundo as diretrizes brasileiras?', '["< 130/80 mmHg", "< 140/90 mmHg", "< 150/90 mmHg", "< 120/80 mmHg", "< 160/100 mmHg"]'::jsonb, 0, 'Cardiologia', 'Hipertensão arterial sistêmica', 'media', 'Para pacientes hipertensos de alto risco (DM, DRC, DAC estabelecida), a meta é < 130/80 mmHg. Para a população geral, aceita-se < 140/90 mmHg.'),
('Paciente de 58 anos com HAS e DM tipo 2, sem contraindicações. Qual classe de anti-hipertensivo é preferencial nesse cenário?', '["Inibidor da ECA ou BRA", "Betabloqueador", "Bloqueador de canal de cálcio dihidropiridínico", "Diurético tiazídico", "Alfabloqueador"]'::jsonb, 0, 'Cardiologia', 'Hipertensão arterial sistêmica', 'media', 'IECA ou BRA são preferidos em diabéticos com HAS pela nefroproteção adicional — reduzem a progressão de microalbuminúria para nefropatia franca.'),
('Qual combinação de fármacos demonstrou redução de mortalidade em insuficiência cardíaca com fração de ejeção reduzida (ICFEr)?', '["IECA + betabloqueador + antagonista da aldosterona", "Digoxina + furosemida + IECA", "Bloqueador de canal de cálcio + IECA + diurético", "Amiodarona + betabloqueador + espironolactona", "Hidralazina + nitratos + digoxina"]'::jsonb, 0, 'Cardiologia', 'Insuficiência cardíaca', 'dificil', 'A tríade IECA (ou BRA/ARNI) + betabloqueador + antagonista da aldosterona reduz mortalidade em ICFEr. Dapagliflozina e sacubitril/valsartana são adições mais recentes com benefício comprovado.'),
('Homem de 65 anos com dispneia progressiva, B3, crepitações bibasais e fração de ejeção de 35%. Qual diurético é mais indicado para alívio sintomático?', '["Furosemida", "Hidroclorotiazida", "Espironolactona", "Triantereno", "Acetazolamida"]'::jsonb, 0, 'Cardiologia', 'Insuficiência cardíaca', 'facil', 'Furosemida (de alça) é o diurético de escolha para descongestão em IC descompensada. Espironolactona é usada pela neuro-hormonal, não para alívio rápido de edema.'),
('Homem de 60 anos com angina estável. Qual exame é mais utilizado para estratificação não invasiva de risco?', '["Teste ergométrico", "Ecocardiograma em repouso", "Ressonância magnética cardíaca", "Holter 24h", "Cateterismo cardíaco de rotina"]'::jsonb, 0, 'Cardiologia', 'Doença arterial coronariana', 'media', 'O teste ergométrico é o exame de primeira linha para estratificação na angina estável. O cateterismo fica para casos de alto risco ou falha do tratamento clínico.'),
('Qual é o mecanismo principal das estatinas no tratamento da DAC, além da redução do LDL?', '["Efeito pleiotrópico anti-inflamatório e estabilização de placa", "Redução de triglicerídeos", "Aumento do HDL", "Vasodilatação coronariana direta", "Inibição da agregação plaquetária"]'::jsonb, 0, 'Cardiologia', 'Doença arterial coronariana', 'dificil', 'Além de reduzir LDL, estatinas têm efeito pleiotrópico: reduzem inflamação (PCR), estabilizam a placa aterosclerótica e melhoram a função endotelial.'),
('Qual é a principal causa do IAM com supradesnivelamento do segmento ST (IAMCSST)?', '["Rotura de placa aterosclerótica com trombose oclusiva", "Vasoespasmo coronariano isolado", "Embolia coronariana", "Dissecção aórtica", "Miocardite aguda"]'::jsonb, 0, 'Cardiologia', 'Síndromes coronarianas agudas', 'facil', 'O IAMCSST é causado pela rotura de placa vulnerável com formação de trombo oclusivo, levando à isquemia transmural. A reperfusão precoce (angioplastia primária) é o tratamento padrão.'),
('Paciente com dor torácica e supradesnivelamento do ST em V1-V4. Não há laboratório de hemodinâmica disponível. Qual conduta?', '["Trombolítico sistêmico (alteplase)", "Observação e repetição do ECG", "Betabloqueador EV imediato", "Cirurgia de revascularização de emergência", "Cardioversão elétrica"]'::jsonb, 0, 'Cardiologia', 'Síndromes coronarianas agudas', 'media', 'Na ausência de laboratório de hemodinâmica, a trombólise com alteplase está indicada se o paciente chegar dentro de 12h do início dos sintomas e não houver contraindicações.'),
('Qual arritmia é caracterizada por ativação atrial rápida e irregular, sem ondas P definidas, levando a resposta ventricular irregular?', '["Fibrilação atrial", "Flutter atrial", "Taquicardia supraventricular paroxística", "Síndrome de Wolff-Parkinson-White", "Taquicardia ventricular"]'::jsonb, 0, 'Cardiologia', 'Arritmias cardíacas', 'facil', 'A FA é caracterizada por atividade atrial caótica (ausência de ondas P), resposta ventricular irregularmente irregular e risco de tromboembolismo (CHADS₂-VASc).'),
('Paciente com FA não valvar e escore CHA₂DS₂-VASc = 3. Qual a conduta antitrombótica?', '["Anticoagulação oral com NOACs (rivaroxabana, apixabana)", "Apenas AAS 100 mg/dia", "Sem anticoagulação", "Heparina de baixo peso molecular indefinidamente", "Dupla antiagregação"]'::jsonb, 0, 'Cardiologia', 'Arritmias cardíacas', 'dificil', 'CHA₂DS₂-VASc ≥ 2 (homens) ou ≥ 3 (mulheres) indica anticoagulação. NOACs são preferidos sobre warfarina pela eficácia e menor risco de sangramento intracraniano.'),
('Qual sopro é característico da estenose aórtica grave?', '["Sopro sistólico ejetivo em foco aórtico com irradiação para carótidas", "Sopro diastólico em foco mitral", "Sopro holossistólico em ápice", "Sopro contínuo em maquinaria", "Sopro diastólico em foco aórtico"]'::jsonb, 0, 'Cardiologia', 'Valvopatias', 'facil', 'A estenose aórtica grave produz sopro sistólico ejetivo (romboidal) no 2º EICD, com irradiação para as carótidas. A tríade clínica clássica: angina, síncope e dispneia.'),
('Mulher de 35 anos com febre reumática na infância apresenta estenose mitral moderada. Qual achado ao ecocardiograma confirma a indicação de valvuloplastia?', '["Área valvar mitral < 1,5 cm² com anatomia favorável", "Fração de ejeção < 40%", "Gradiente médio < 5 mmHg", "Pressão sistólica pulmonar < 35 mmHg", "Área valvar > 2,0 cm²"]'::jsonb, 0, 'Cardiologia', 'Valvopatias', 'dificil', 'A valvuloplastia mitral por balão é indicada quando área < 1,5 cm² com morfologia favorável (escore de Wilkins ≤ 8), ausência de trombo atrial e regurgitação mitral significativa.'),
('Qual miocardiopatia é caracterizada por hipertrofia ventricular esquerda assimétrica, obstrução dinâmica da via de saída e é causa comum de morte súbita em jovens?', '["Miocardiopatia hipertrófica", "Miocardiopatia dilatada", "Miocardiopatia restritiva", "Displasia arritmogênica do VD", "Miocardite viral"]'::jsonb, 0, 'Cardiologia', 'Miocardiopatias', 'media', 'A MCH é genética (autossômica dominante, gene da miosina cardíaca). A obstrução dinâmica da VSVE e a hipertrofia assimétrica predispõem a morte súbita, especialmente em atletas jovens.'),
('Paciente com miocardiopatia dilatada, FE = 25%, sem melhora com terapia clínica otimizada. Qual dispositivo reduz mortalidade?', '["CDI (cardiodesfibrilador implantável)", "Marcapasso convencional", "Ressincronizador cardíaco isolado", "Balão intra-aórtico", "Dispositivo de assistência ventricular definitivo"]'::jsonb, 0, 'Cardiologia', 'Miocardiopatias', 'dificil', 'O CDI reduz morte súbita arrítmica em pacientes com FE ≤ 35% e terapia clínica otimizada ≥ 3 meses. Se QRS > 150ms com BRE, a terapia de ressincronização (CRT-D) é preferida.'),
('Qual é o tratamento de primeira linha da pericardite aguda idiopática/viral?', '["AAS ou ibuprofeno + colchicina", "Corticosteroides em altas doses", "Antibióticos de amplo espectro", "Pericardiocentese de urgência", "Repouso absoluto sem farmacoterapia"]'::jsonb, 0, 'Cardiologia', 'Pericardite e miocardite', 'facil', 'AINEs (AAS ou ibuprofeno) + colchicina por 3 meses reduzem sintomas e recorrência. Corticoides são reservados para falha dos AINEs ou etiologias específicas (lúpus), pois aumentam recorrência.'),
('Paciente jovem com dor torácica pleurítica, atrito pericárdico e elevação difusa do ST côncavo. Qual exame confirma o diagnóstico?', '["ECG com padrão difuso de elevação do ST côncavo", "Troponina elevada isolada", "Ecocardiograma com FE reduzida", "Cateterismo com obstrução coronariana", "Ressonância com realce tardio subepicárdico"]'::jsonb, 0, 'Cardiologia', 'Pericardite e miocardite', 'media', 'O ECG da pericardite aguda mostra elevação difusa do ST côncavo (sela), depressão do segmento PR e ausência de alterações recíprocas — diferenciando do IAM.'),
('Paciente com febre, sopro cardíaco novo e bacteremia por Staphylococcus aureus. Qual critério de Duke está presente?', '["1 critério maior (hemocultura positiva) + 1 critério menor (febre)", "Apenas critérios menores", "2 critérios menores", "Diagnóstico rejeitado", "Critério definitivo isolado"]'::jsonb, 0, 'Cardiologia', 'Endocardite infecciosa', 'dificil', 'Os critérios de Duke: maiores (2 hemoculturas+ com S. aureus, vegetação ao eco) e menores (febre, sopro, fatores predisponentes). Diagnóstico definitivo: 2 maiores, 1 maior + 3 menores, ou 5 menores.'),
('Qual é a duração mínima do tratamento antibiótico na endocardite por Streptococcus viridans sensível à penicilina em valva nativa?', '["4 semanas", "2 semanas", "6 semanas", "8 semanas", "Até negativação das hemoculturas"]'::jsonb, 0, 'Cardiologia', 'Endocardite infecciosa', 'media', 'Streptococcus sensível à penicilina em valva nativa: tratamento de 4 semanas com penicilina G ou ceftriaxona. Regimes de 2 semanas são aceitáveis em casos selecionados de baixo risco.'),
('Qual é a principal causa de hipertensão pulmonar no mundo?', '["Doença cardíaca esquerda (grupo 2)", "HAP idiopática (grupo 1)", "DPOC (grupo 3)", "TEP crônico (grupo 4)", "Doença autoimune (grupo 1)"]'::jsonb, 0, 'Cardiologia', 'Hipertensão pulmonar', 'media', 'A hipertensão pulmonar do grupo 2 (doença cardíaca esquerda: IC, valvopatias) é a forma mais prevalente globalmente. A HAP idiopática (grupo 1) é mais rara porém grave.'),
('Qual fármaco específico para HAP atua como antagonista dos receptores de endotelina?', '["Bosentana", "Sildenafila", "Epoprostenol", "Riociguata", "Treprostinila"]'::jsonb, 0, 'Cardiologia', 'Hipertensão pulmonar', 'dificil', 'Bosentana é antagonista não seletivo dos receptores de endotelina A e B. Outros: ambrisentana e macitentana. Sildenafila é inibidor de PDE5; epoprostenol é análogo de prostaciclina.'),
('Paciente com dispneia súbita, taquicardia e hipoxemia. O escore de Wells = 7. Qual conduta inicial?', '["Anticoagulação empírica enquanto aguarda imagem", "Aguardar D-dímero antes de anticoagulaçäo", "Trombolítico imediato", "Ecocardiograma obrigatório antes de qualquer tratamento", "Alta com heparina profilática"]'::jsonb, 0, 'Cardiologia', 'Tromboembolismo pulmonar', 'media', 'Wells ≥ 5 = alta probabilidade de TEP. A anticoagulação deve ser iniciada empiricamente (heparina EV ou HBPM) enquanto a angiotomografia é realizada, pois o risco de retardar supera o risco de sangramento.'),
('Qual sinal eletrocardiográfico clássico, embora pouco sensível, está associado ao TEP?', '["Padrão S1Q3T3", "Elevação do ST em V1-V4", "Ondas Q patológicas em DIII", "BAV de 1º grau", "QT longo"]'::jsonb, 0, 'Cardiologia', 'Tromboembolismo pulmonar', 'facil', 'O padrão S1Q3T3 (onda S em DI, onda Q e inversão de T em DIII) reflete a sobrecarga aguda do ventrículo direito no TEP. Taquicardia sinusal é a alteração mais frequente.'),
('Paciente de 70 anos com dor torácica em rasgo, irradiando para o dorso, HAS. TC mostra dissecção desde a aorta ascendente. Qual classificação e tratamento?', '["Stanford tipo A — cirurgia de emergência", "Stanford tipo B — tratamento clínico", "DeBakey tipo III — cirurgia eletiva", "Stanford tipo A — tratamento clínico com nitroprussiato", "Stanford tipo B — cirurgia de emergência"]'::jsonb, 0, 'Cardiologia', 'Doenças da aorta', 'dificil', 'Dissecção Stanford tipo A envolve a aorta ascendente — tratamento cirúrgico de emergência (alta mortalidade sem cirurgia). Tipo B (distal à artéria subclávia esquerda) = tratamento clínico salvo complicações.'),
('Qual é o principal fator de risco para aneurisma de aorta abdominal?', '["Tabagismo", "Diabetes mellitus", "Obesidade", "Hipotireoidismo", "Sedentarismo"]'::jsonb, 0, 'Cardiologia', 'Doenças da aorta', 'media', 'Tabagismo é o principal fator de risco modificável para AAA, associado a 75% dos casos. A rastreamento com USG é recomendado para homens > 65 anos tabagistas.'),
('Qual é o critério diagnóstico de diabetes mellitus pela glicemia de jejum?', '["≥ 126 mg/dL em duas ocasiões", "≥ 100 mg/dL em duas ocasiões", "≥ 200 mg/dL em uma ocasião", "≥ 110 mg/dL em duas ocasiões", "≥ 140 mg/dL em 2h no TOTG"]'::jsonb, 0, 'Clínica Médica', 'Diabetes mellitus', 'facil', 'Diabetes: glicemia de jejum ≥ 126 mg/dL (2 dosagens), TOTG ≥ 200 mg/dL em 2h, HbA1c ≥ 6,5% ou glicemia aleatória ≥ 200 mg/dL com sintomas.'),
('Qual é a meta de HbA1c recomendada para a maioria dos diabéticos adultos segundo as diretrizes?', '["< 7%", "< 6%", "< 8%", "< 9%", "< 6,5%"]'::jsonb, 0, 'Clínica Médica', 'Diabetes mellitus', 'facil', 'A meta geral é HbA1c < 7%. Para idosos frágeis ou com múltiplas comorbidades, metas menos rígidas (< 8%) são aceitáveis para reduzir hipoglicemias.'),
('Quais são os critérios de disfunção orgânica na definição de Sepse-3?', '["Aumento de ≥ 2 pontos no escore SOFA", "Presença de dois critérios SIRS", "Temperatura > 38°C + leucocitose", "Hipotensão isolada", "PCR > 10 mg/dL"]'::jsonb, 0, 'Clínica Médica', 'Sepse e choque', 'dificil', 'Sepse-3 define sepse como disfunção orgânica ameaçadora à vida por resposta desregulada à infecção, representada por SOFA ≥ 2. SIRS não é mais critério diagnóstico.'),
('Qual é o volume de cristaloide recomendado na ressuscitação inicial do choque séptico?', '["30 mL/kg nas primeiras 3 horas", "1 L/h indefinidamente", "10 mL/kg em bolus rápido", "50 mL/kg em 6 horas", "Sem indicação de fluido — vasopresor direto"]'::jsonb, 0, 'Clínica Médica', 'Sepse e choque', 'media', 'O bundle de 1 hora da Surviving Sepsis Campaign recomenda 30 mL/kg de cristaloide (SF 0,9% ou Ringer lactato) nas primeiras 3 horas no choque séptico, com reavaliação dinâmica.'),
('Qual é o fármaco de resgate de primeira linha para crise de asma leve a moderada?', '["Beta-2 agonista de curta ação (salbutamol)", "Corticoide inalatório", "Brometo de ipratrópio isolado", "Teofilina EV", "Adrenalina IM"]'::jsonb, 0, 'Pneumologia', 'Asma', 'facil', 'Salbutamol (SABA) é o broncodilatador de resgate padrão na asma. Brometo de ipratrópio é adicionado em crises moderadas a graves. Corticosteroides sistêmicos são usados em crises moderadas/graves.'),
('Qual marcador inflamatório sérico auxilia na identificação de asma eosinofílica com indicação de biológicos?', '["Eosinófilos periféricos e FeNO", "PCR", "IgG total", "VHS", "Procalcitonina"]'::jsonb, 0, 'Pneumologia', 'Asma', 'dificil', 'Asma eosinofílica grave: eosinófilos > 300/μL e/ou FeNO > 50 ppb indicam inflamação Th2 e boa resposta a biológicos anti-IL-5 (mepolizumabe) ou anti-IL-4Rα (dupilumabe).'),
('Qual espirometria confirma DPOC?', '["VEF1/CVF < 0,70 pós-broncodilatador", "VEF1 < 80% do previsto", "CVF < 80% do previsto", "VEF1/CVF < 0,70 pré-broncodilatador", "DLCO < 70% do previsto"]'::jsonb, 0, 'Pneumologia', 'DPOC', 'facil', 'O diagnóstico de DPOC requer VEF1/CVF < 0,70 pós-broncodilatador (critério fixo da GOLD). Isso distingue obstrução permanente do broncoespasmo reversível.'),
('Qual é o esquema básico para tuberculose pulmonar sem resistência em adultos no Brasil?', '["RHZE por 2 meses + RH por 4 meses", "RH por 6 meses", "RHZE por 6 meses", "Estreptomicina + isoniazida por 9 meses", "Apenas isoniazida por 12 meses"]'::jsonb, 0, 'Pneumologia', 'Tuberculose', 'media', 'O esquema DOTS brasileiro: rifampicina (R) + isoniazida (H) + pirazinamida (Z) + etambutol (E) por 2 meses, depois RH por 4 meses = total 6 meses (comprimido 4 em 1).'),
('Paciente com hemiplegia esquerda aguda e tomografia sem sangramento. Dentro de qual janela temporal o rt-PA é indicado?', '["Até 4,5 horas do início dos sintomas", "Até 6 horas", "Até 12 horas", "Até 24 horas", "Apenas se NIHSS > 20"]'::jsonb, 0, 'Neurologia', 'Acidente vascular cerebral', 'media', 'Trombólise com rt-PA: janela de 4,5h do início dos sintomas, sem contraindicações (TC sem sangramento, PA < 185/110 após controle, glicemia entre 50-400 mg/dL).'),
('Qual é o tratamento de primeira linha para o estado de mal epiléptico convulsivo em adultos?', '["Benzodiazepínico EV (diazepam ou lorazepam)", "Fenitoína EV isolada", "Levetiracetam oral", "Barbitúrico de indução imediata", "Propofol como primeira linha"]'::jsonb, 0, 'Neurologia', 'Epilepsia', 'media', 'Benzodiazepínicos EV (lorazepam ou diazepam) são primeira linha. Se falha: fenitoína/fosfenitoína ou valproato EV. Estado refratário: midazolam, propofol ou barbitúrico em UTI.'),
('Qual critério temporal define o transtorno depressivo maior (DSM-5)?', '["Sintomas ≥ 2 semanas com pelo menos 5 critérios", "Sintomas ≥ 1 semana com mania", "Sintomas ≥ 1 mês com alucinações", "Sintomas ≥ 6 meses contínuos", "Apenas anedonia persistente"]'::jsonb, 0, 'Psiquiatria', 'Transtorno depressivo maior', 'facil', 'DSM-5: ≥ 5 sintomas (incluindo humor deprimido e/ou anedonia) por ≥ 2 semanas, causando prejuízo funcional. Humor deprimido ou anedonia deve estar presente.'),
('Qual sintoma positivo é patognomônico de psicose na esquizofrenia?', '["Alucinações auditivas em 3ª pessoa", "Embotamento afetivo", "Alogia", "Avolição", "Déficit cognitivo"]'::jsonb, 0, 'Psiquiatria', 'Esquizofrenia', 'media', 'Sintomas positivos: alucinações (principalmente auditivas comentativas), delírios, desorganização. Sintomas negativos: alogia, avolição, embotamento afetivo, anedonia. Ambos compõem o quadro de esquizofrenia.'),
('Qual é o fármaco de primeira linha no DM2 sem contraindicações?', '["Metformina", "Sulfonilurea", "Insulina basal", "Inibidor de SGLT2", "Agonista de GLP-1"]'::jsonb, 0, 'Endocrinologia', 'Diabetes mellitus tipo 2', 'facil', 'Metformina é a primeira linha no DM2 por eficácia, segurança, baixo custo e efeito neutro/leve na perda de peso. Deve ser associada a mudança de estilo de vida.'),
('Qual é o hormônio de rastreamento inicial para hipotireoidismo?', '["TSH", "T4 livre", "T3 total", "Anticorpos anti-TPO", "TRH"]'::jsonb, 0, 'Endocrinologia', 'Hipotireoidismo', 'facil', 'TSH é o melhor marcador de função tireoidiana: elevado no hipotireoidismo primário, baixo no hipertireoidismo. T4 livre é complementar para graduar a deficiência.'),
('Qual é o tratamento de primeira linha da artrite reumatoide ativa?', '["Metotrexato", "Prednisona isolada", "Hidroxicloroquina isolada", "Biológico anti-TNF imediato", "AINE como monoterapia"]'::jsonb, 0, 'Reumatologia', 'Artrite reumatoide', 'media', 'Metotrexato (MTX) é o DMCD âncora da AR. Deve ser iniciado precocemente (< 3 meses do diagnóstico). Biológicos são adicionados em falha de MTX ou doença grave.'),
('Qual anticorpo é mais específico para LES e está associado a nefrite lúpica ativa?', '["Anti-DNA dupla-fita (anti-dsDNA)", "FAN (ANA) isolado", "Anti-Ro/SSA", "Anti-histona", "Anti-centrômero"]'::jsonb, 0, 'Reumatologia', 'Lúpus eritematoso sistêmico', 'dificil', 'Anti-dsDNA é altamente específico para LES (~95%) e seus títulos correlacionam com atividade da doença, especialmente nefrite lúpica. FAN é sensível mas não específico.'),
('Qual é o achado típico da anemia ferropriva no hemograma?', '["Microcitose e hipocromia com RDW elevado", "Macrocitose com hipersegmentação", "Normocitose com reticulocitose", "Pancitopenia", "Microcitose com RDW normal"]'::jsonb, 0, 'Hematologia', 'Anemia ferropriva', 'facil', 'Anemia ferropriva: microcitose (VCM < 80 fL), hipocromia (HCM < 27 pg), RDW elevado (anisocitose). Ferritina baixa confirma o diagnóstico.'),
('Qual é o anticoagulante preferencial na TVP associada ao câncer?', '["Heparina de baixo peso molecular (HBPM)", "Warfarina", "Rivaroxabana", "AAS", "Fondaparinux"]'::jsonb, 0, 'Hematologia', 'Trombose venosa profunda', 'dificil', 'Em TVP/TEP associados ao câncer, HBPM por 3-6 meses é tradicional. Estudos recentes mostram que apixabana e rivaroxabana são alternativas (exceto em tumores GI/urológicos pelo risco de sangramento).'),
('Quando está indicado iniciar terapia antirretroviral (TARV) em paciente com HIV?', '["Independente da contagem de CD4", "Apenas quando CD4 < 200 células/mm³", "Apenas quando CD4 < 350 células/mm³", "Somente se sintomático", "Após 6 meses do diagnóstico"]'::jsonb, 0, 'Infectologia', 'HIV/AIDS', 'media', 'Diretrizes atuais (OMS e MS Brasil): TARV para todos com HIV, independente do CD4, pois reduz transmissão, morbidade e mortalidade. Início imediato (''test and treat'').'),
('Qual é a principal forma de transmissão da tuberculose?', '["Via aérea por gotículas (núcleos de Wells)", "Contato direto com secreções", "Via fecal-oral", "Picada de vetor", "Transmissão vertical"]'::jsonb, 0, 'Infectologia', 'Tuberculose', 'facil', 'M. tuberculosis é transmitido por aerossóis (núcleos de Wells < 5μm) que ficam suspensos no ar. Contato prolongado em ambientes fechados é o principal cenário de transmissão.'),
('Aos 2 meses de vida, quais vacinas do calendário nacional são aplicadas?', '["Penta (DTP+Hib+HepB), VIP, Pneumo 10, Rotavírus", "BCG, Hepatite B, VIP", "Penta, VIP, Meningocócica C", "Tríplice viral, Varicela, Hepatite A", "BCG e Hepatite B apenas"]'::jsonb, 0, 'Pediatria', 'Vacinação e puericultura', 'facil', 'Aos 2 meses: Penta (DTP+Hib+HepB), VIP (polio inativada), Pneumocócica 10-valente e Rotavírus humano. BCG e Hepatite B são ao nascer (ou no 1º mês).'),
('Recém-nascido com Apgar 5 no 1º minuto e 7 no 5º minuto. Como classificar?', '["Asfixia leve com boa recuperação", "Óbito neonatal iminente", "Asfixia grave com sequela neurológica", "Bebê saudável sem intervenção", "Asfixia moderada sem recuperação"]'::jsonb, 0, 'Pediatria', 'Neonatologia', 'media', 'Apgar ≥ 7: normal. 4-6: asfixia leve/moderada. ≤ 3: asfixia grave. Apgar de 5 no 1'' com melhora para 7 no 5'' indica boa resposta às manobras de reanimação — prognóstico favorável.'),
('Qual é a definição de pré-eclâmpsia?', '["PA ≥ 140/90 mmHg após 20 semanas + proteinúria ou disfunção orgânica", "PA > 160/110 mmHg em qualquer semana", "Edema + cefaleia + proteinúria a qualquer momento", "HAS crônica com PA > 140/90 mmHg", "PA ≥ 130/85 mmHg + edema"]'::jsonb, 0, 'Ginecologia e Obstetrícia', 'Síndromes hipertensivas da gestação', 'media', 'Pré-eclâmpsia: PA ≥ 140/90 mmHg após 20 semanas de gestação COM proteinúria significativa (≥ 300 mg/24h) OU sinais de disfunção de órgão-alvo (trombocitopenia, disfunção renal/hepática, edema pulmonar, sintomas neurológicos).'),
('Qual é o mecanismo de ação principal do DIU de cobre?', '["Efeito espermicida e inflamatório local", "Inibição da ovulação", "Espessamento do muco cervical", "Inibição da implantação primariamente", "Atrofia do endométrio"]'::jsonb, 0, 'Ginecologia e Obstetrícia', 'Contracepção', 'dificil', 'O DIU de cobre exerce efeito espermicida (ions Cu²⁺ são tóxicos para espermatozoides) e provoca reação inflamatória local que impede fertilização. É o contraceptivo de emergência não hormonal mais eficaz.'),
('Qual é a escala mais utilizada para diagnóstico de apendicite aguda?', '["Escore de Alvarado", "Escore de Ranson", "Escore de Wells", "Índice de Mannheim", "Critérios de Duke"]'::jsonb, 0, 'Cirurgia Geral', 'Apendicite aguda', 'facil', 'O escore de Alvarado pontua: migração de dor, anorexia, náuseas/vômitos, defesa de FID, dor em FID, febre, leucocitose e desvio à esquerda. ≥ 7 = alta probabilidade de apendicite.'),
('Qual é o exame de imagem de escolha para diagnóstico de abdome agudo obstrutivo em adultos?', '["Tomografia computadorizada de abdome", "Radiografia simples de abdome", "Ultrassonografia abdominal", "RNM de abdome", "Enema opaco"]'::jsonb, 0, 'Cirurgia Geral', 'Abdome agudo', 'media', 'TC de abdome com contraste é o padrão-ouro para avaliar obstrução intestinal — determina nível, causa e sinais de sofrimento alçal (pneumatose, espessamento, ausência de realce). Rx é triagem inicial.'),
('Qual regra mnemônica é usada para avaliação clínica de lesões melanocíticas suspeitas?', '["ABCDE (Assimetria, Borda, Cor, Diâmetro, Evolução)", "SORS (Sangramento, Oleosidade, Rugosidade, Superfície)", "PEST (Pigmentação, Espessura, Superfície, Textura)", "RIPE (Região, Intensidade, Progressão, Extensão)", "PRICE (Pruridão, Ressecamento, Inflamação, Cor, Extensão)"]'::jsonb, 0, 'Dermatologia', 'Melanoma', 'facil', 'ABCDE: Assimetria, Borda irregular, Cor variegada, Diâmetro > 6mm, Evolução. Qualquer critério presente justifica biópsia excisional. O melanoma é o tumor cutâneo com maior mortalidade.'),
('Qual é o tratamento biológico de primeira linha para psoríase moderada a grave?', '["Inibidores de TNF (adalimumabe, etanercepte) ou IL-17/23", "Corticoide tópico potente isolado", "Metotrexato oral", "Ciclosporina", "Fototerapia PUVA"]'::jsonb, 0, 'Dermatologia', 'Psoríase', 'dificil', 'Psoríase moderada-grave (PASI > 10 ou impacto severo na qualidade de vida): biológicos anti-TNF, anti-IL-17 (secuquinumabe) ou anti-IL-23 (guselcumabe) são altamente eficazes. MTX e ciclosporina são opções convencionais.'),
('Qual é o principal fator de risco para glaucoma de ângulo aberto?', '["Pressão intraocular elevada", "Miopia extrema", "Diabetes mellitus", "Hipertensão arterial", "Uso prolongado de AINEs"]'::jsonb, 0, 'Oftalmologia', 'Glaucoma', 'facil', 'PIO elevada é o principal fator de risco modificável para glaucoma. O diagnóstico é clínico-funcional (campo visual + OCT de nervo óptico); PIO normal não exclui glaucoma.'),
('Qual é o tratamento de primeira linha para edema macular diabético clinicamente significativo?', '["Injeção intravítrea de anti-VEGF", "Fotocoagulação laser imediata", "Corticoide intravítreo", "Cirurgia vitreorretiniana", "Controle glicêmico isolado"]'::jsonb, 0, 'Oftalmologia', 'Retinopatia diabética', 'dificil', 'Anti-VEGF intravítreo (bevacizumabe, ranibizumabe, aflibercepte) é a terapia de primeira linha para edema macular diabético, com superiores resultados visuais em relação ao laser.'),
('Qual é o tratamento farmacológico de primeira linha para HPB com sintomas moderados?', '["Alfabloqueador (tansulosina, alfuzosina)", "Inibidor de 5-alfa-redutase isolado", "Anticolinérgico", "Antibiótico", "Diurético"]'::jsonb, 0, 'Urologia', 'Hiperplasia prostática benigna', 'facil', 'Alfabloqueadores relaxam a musculatura lisa do colo vesical e próstata — alívio sintomático rápido. Inibidores de 5-alfa-redutase (finasterida) reduzem volume prostático mas têm latência de 6 meses.'),
('Qual é o tratamento de escolha para cálculo ureteral < 10 mm em paciente estável?', '["Tratamento expectante com terapia expulsiva (alfabloqueador)", "Cirurgia imediata", "Litotripsia extracorpórea", "Ureteroscopia de urgência", "Nefrolitotomia percutânea"]'::jsonb, 0, 'Urologia', 'Litíase urinária', 'media', 'Cálculos < 10 mm têm 70-80% de chance de expulsão espontânea. Terapia expulsiva com tansulosina acelera a eliminação. Indicações de intervenção: obstrução, infecção, dor refratária, falha expulsiva.');